"use client"

import Link from "next/link"
import { useState } from "react"
import { Button, Typography, Input } from "@/components/ui"
import { LogoIcon } from "@/components/icons"

const Signup = () => {
  const [name, setName] = useState("")
  const [gender, setGender] = useState("")
  const [email, setEmail] = useState("")

  return (
    <>
      <LogoIcon />

      <Typography variant="intro" className="mt-10 mb-4">Sign up on Smile Agrimarket</Typography>

      <Input
        label="Enter your Fullname"
        id="name"
        type="text"
        value={name}
        onChange={e => setName(e.target.value)}
        className="mb-4"
      />

      <Select
        options={referralOptions}
        value={referralOptions.find(opt => opt.value === referral) ? referral : ''}
        onChange={e => setReferral(e.target.value as string)}
        placeholder="Select a referral source..."
        className="mb-4"
      />

      <Input
        label="Enter your phone number"
        id="name"
        type="text"
        value={gender}
        onChange={e => setGender(e.target.value)}
        className="mb-4"
      />

      <Input
        label="Enter your email address"
        id="email"
        type="text"
        value={email}
        onChange={e => setEmail(e.target.value)}
        bottomText="Please confirm that your email address is valid"
      />

      <Link href="/onboarding" className="w-full">
        <Button
          variant="primary"
          className="w-full uppercase mt-4"
          size="large"
          type="submit"
          disabled={!email}
        >
          continue
        </Button>
      </Link>
    </>
  )
}

export default Signup